-- V12 pointed images at upload.wikimedia.org directly, but this network
-- environment has very poor/unreliable connectivity to Wikimedia's media
-- servers specifically (confirmed: Cloudflare-fronted hosts load fine,
-- Wikimedia requests hang indefinitely on-device even though they succeed,
-- slowly, from a desktop). Embed the photos as base64 data URIs instead --
-- zero network dependency, same mechanism already used for marketplace
-- compose uploads. Images are small (3-13KB), resized to fit comfortably.

UPDATE product_batches pb SET image_url = f.new_url
FROM (VALUES
  ('https://upload.wikimedia.org/wikipedia/commons/3/3e/Bissap.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/b/b1/Bottled_water.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/b/b7/Canned_tomatoes.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/a/a3/White_rice.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/d/df/Wheat_flour.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/c/c7/Cooking_oil.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/a/ad/Glass_of_milk_on_tablecloth.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/a/a8/Biszkopt.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/f/fa/Groundnuts.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/7/7c/Spices.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/4/49/Paracetamol.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/7/7f/Pills.jpg', 'data:image/jpeg;base64,')
) AS f(old_url, new_url)
WHERE f.old_url = pb.image_url;

UPDATE drug_batches db SET image_url = f.new_url
FROM (VALUES
  ('https://upload.wikimedia.org/wikipedia/commons/4/49/Paracetamol.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/7/7f/Pills.jpg', 'data:image/jpeg;base64,')
) AS f(old_url, new_url)
WHERE f.old_url = db.image_url;

UPDATE marketplace_posts mp SET image_url = f.new_url
FROM (VALUES
  ('https://upload.wikimedia.org/wikipedia/commons/3/3e/Bissap.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/b/b1/Bottled_water.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/b/b7/Canned_tomatoes.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/a/a3/White_rice.jpg', 'data:image/jpeg;base64,'),
  ('https://upload.wikimedia.org/wikipedia/commons/4/49/Paracetamol.jpg', 'data:image/jpeg;base64,')
) AS f(old_url, new_url)
WHERE f.old_url = mp.image_url;
